import base64, gzip, hashlib, io, json, random
from datetime import datetime, timezone
from pathlib import Path
import pandas as pd
import streamlit as st

st.set_page_config(page_title="TES Leixa — Test táctil", page_icon="🚑", layout="wide")

VERSION = "Banco v8.06 · correcciones coherentes por concepto"
USER_STORE_PATH = Path("user_store.json")

INITIAL_PASSWORDS = {
    "diego": "tes2026",
    "anton": "1234",
    "melisa": "1111",
    "elvira": "2222",
    "lucia": "3333",
}
BANK_B64 = """"""

def now_iso():
    return datetime.now(timezone.utc).isoformat()

def n(value):
    if pd.isna(value):
        return ""
    return str(value).strip()

def hp(password, salt):
    return hashlib.sha256((salt + password).encode("utf-8")).hexdigest()

def default_store():
    def u(uid, name, pwd, role, must):
        salt = hashlib.sha256((uid + pwd + "v802").encode("utf-8")).hexdigest()[:16]
        return {"display_name": name, "salt": salt, "password_hash": hp(pwd, salt), "role": role, "active": True, "must_change_password": must}
    users = {
        "diego": u("diego","Diego","tes2026","administrador",False),
        "anton": u("anton","Anton","1234","usuario",True),
        "melisa": u("melisa","Melisa","1111","usuario",True),
        "elvira": u("elvira","Elvira","2222","usuario",True),
        "lucia": u("lucia","Lucia","3333","usuario",True),
    }
    return {"schema_version":"8.02","updated_at":now_iso(),"users":users,"progress":{uid:{"answered":[],"wrong_ids":[],"correct_ids":[],"settings":{"daily_goal":148}} for uid in users}}

def ensure_store(store):
    base = default_store()
    store.setdefault("users", {})
    store.setdefault("progress", {})
    for uid, user in base["users"].items():
        store["users"].setdefault(uid, user)
    for uid in store["users"]:
        store["progress"].setdefault(uid, {"answered": [], "wrong_ids": [], "correct_ids": [], "settings": {"daily_goal": 148}})
        store["progress"][uid].setdefault("answered", [])
        store["progress"][uid].setdefault("wrong_ids", [])
        store["progress"][uid].setdefault("correct_ids", [])
        store["progress"][uid].setdefault("settings", {"daily_goal": 148})
    return store

def load_store():
    if USER_STORE_PATH.exists():
        try:
            return ensure_store(json.loads(USER_STORE_PATH.read_text(encoding="utf-8"))), "Archivo local"
        except Exception as exc:
            return default_store(), f"Nuevo por error: {exc}"
    store = default_store()
    save_store(store)
    return store, "Archivo local creado"

def save_store(store):
    try:
        store["updated_at"] = now_iso()
        USER_STORE_PATH.write_text(json.dumps(store, ensure_ascii=False, indent=2), encoding="utf-8")
        return True, "Guardado OK"
    except Exception as exc:
        return False, f"Error guardando: {exc}"

@st.cache_data(show_spinner=False)
def load_bank():
    raw = base64.b64decode(BANK_B64)
    with gzip.GzipFile(fileobj=io.BytesIO(raw), mode="rb") as gz:
        df = pd.read_csv(gz, dtype=str, encoding="utf-8-sig").fillna("")
    if "cuadro_aprendizaje" not in df.columns:
        df["cuadro_aprendizaje"] = df.get("tabla_esquema", "")
    df["respuesta_correcta"] = df["respuesta_correcta"].astype(str).str.upper().str.strip()
    return df[df["respuesta_correcta"].isin(["A","B","C","D"])].reset_index(drop=True)

def repair_user_password(store, uid, password):
    """Repara hash si el user_store quedó viejo/corrupto."""
    uid = uid.strip().lower()
    user = store.get("users", {}).get(uid)
    if not user:
        return None
    salt = hashlib.sha256((uid + password + "v802").encode("utf-8")).hexdigest()[:16]
    user["salt"] = salt
    user["password_hash"] = hp(password, salt)
    user["updated_at"] = now_iso()
    return user


def auth(store, uid, pwd):
    uid = uid.strip().lower()
    user = store.get("users", {}).get(uid)
    if not user or not user.get("active", False):
        return None

    # 1) Login normal con el hash actual del archivo.
    try:
        if hp(pwd, user["salt"]) == user["password_hash"]:
            return user
    except Exception:
        pass

    # 2) Rescate: si coincide con contraseña inicial, repara el usuario.
    if uid in INITIAL_PASSWORDS and pwd == INITIAL_PASSWORDS[uid]:
        repaired = repair_user_password(store, uid, pwd)
        save_store(store)
        return repaired

    return None

def progress(store, uid):
    ensure_store(store)
    return store["progress"][uid]

def opt(q, L):
    return n(q.get({"A":"opcion_a","B":"opcion_b","C":"opcion_c","D":"opcion_d"}[L], ""))

def why(q, L):
    return n(q.get(f"porque_no_{L.lower()}", ""))

def seen_ids(p):
    return {str(x.get("id","")) for x in p.get("answered", [])}


def concept_override_table(q):
    blob = " ".join(n(q.get(k, "")) for k in ["enunciado","tema","subtema","conceptos_clave","opcion_a","opcion_b","opcion_c","opcion_d","explicacion"]).lower()
    if any(x in blob for x in ["medular", "cervical", "torácica", "toracica", "plexo braquial", "ambas piernas", "brazos conservados", "paraplej", "tetraplej"]):
        return """### Lesiones medulares por nivel: patrón TES

| Sospecha | Patrón motor/sensitivo esperado | Brazos | Piernas | Clave de examen |
|---|---|---:|---:|---|
| Lesión cervical alta | Déficit en brazos y piernas; puede comprometer respiración si es alta | Afectados | Afectadas | Tetraparesia/tetraplejia o alteración de cuatro extremidades |
| Lesión cervical baja | Déficit en brazos y piernas, a veces brazos parcialmente conservados según nivel | Afectados parcial/variable | Afectadas | Sigue siendo cervical si afecta miembros superiores |
| Lesión medular torácica | Déficit motor/sensitivo en tronco inferior y ambas piernas con brazos conservados | Conservados | Afectadas | Paraparesia/paraplejia: brazos normales + piernas alteradas |
| Lesión lumbar/conos/cauda equina | Déficit en piernas, esfínteres o sensibilidad en silla de montar | Conservados | Afectadas variable | Sospecha si hay alteración esfinteriana o perineal |
| Lesión cortical unilateral | Déficit de un lado del cuerpo, no patrón simétrico de ambas piernas | Variable | Variable | Hemicuerpo, cara/brazo/pierna de un lado |
| Plexo braquial | Déficit en brazo/hombro, no en ambas piernas | Afecta brazo | Conservadas | Lesión periférica de miembro superior |

**Regla de oro:** brazos conservados + ambas piernas afectadas = sospecha torácica o inferior; brazos afectados + piernas afectadas = sospecha cervical."""
    return ""


def render_failure(q, selected, correct):
    st.markdown("## 🚨 Aprendizaje obligatorio del fallo")
    st.markdown(f"### Correcta: **{correct}. {opt(q, correct)}**")
    st.markdown(f"**Tu respuesta:** {selected}. {opt(q, selected)}")

    table = concept_override_table(q) or n(q.get("cuadro_aprendizaje", "")) or n(q.get("tabla_esquema", ""))
    if table:
        st.markdown("### Tabla / esquema")
        st.markdown(table)

    st.markdown("### Explicación")
    st.markdown(n(q.get("explicacion", "")) or "La clave es aplicar el criterio técnico exacto del caso.")

    st.markdown("### Por qué fallaste")
    st.markdown(why(q, selected) or f"{opt(q, selected)} es plausible, pero no encaja con el dato diferencial. Aquí manda {opt(q, correct)}.")

    st.markdown("### Descarte de distractores")
    hay = False
    for L in ["A","B","C","D"]:
        if L != correct:
            txt = why(q, L)
            if txt:
                hay = True
                st.write(f"- **{L}. {opt(q,L)}:** {txt}")
    if not hay:
        for L in ["A","B","C","D"]:
            if L != correct:
                st.write(f"- **{L}. {opt(q,L)}:** distractor cercano, pero no cumple el criterio exacto.")

    st.markdown("### Regla de oro")
    st.markdown(n(q.get("regla_oro", "")) or "Dato diferencial → criterio técnico → respuesta.")

    st.markdown("### Error típico")
    st.markdown(n(q.get("error_tipico", "")) or "Elegir por familiaridad sin comprobar el contexto exacto.")

    st.markdown("### Tip de examen")
    st.markdown(n(q.get("tip_examen", "")) or "Subraya cifras, fase, zona, estructura o signo clínico.")

    st.markdown("### Mini-lección")
    st.markdown(n(q.get("minileccion", "")) or "Concepto → criterio → caso → trampa habitual.")

    mn = n(q.get("mnemotecnia", ""))
    if mn:
        st.markdown("### Mnemotecnia")
        st.markdown(mn)

def init():
    defaults = {
        "store": None, "store_mode": "", "logged": False, "uid": "", "display_name": "", "role": "",
        "queue_key": "", "queue": [], "queue_pos": 0, "answered": False, "selected": None,
        "current_qid": "", "last_save": ""
    }
    for k, v in defaults.items():
        st.session_state.setdefault(k, v)

def build_queue(df, p, mode, module):
    work = df.copy()
    if module != "Todos":
        work = work[work["modulo"] == module]
    seen = seen_ids(p)
    wrong = set(p.get("wrong_ids", []))
    if mode == "Solo no respondidas":
        work = work[~work["id"].isin(seen)]
    elif mode == "Solo mis fallos":
        work = work[work["id"].isin(wrong)]
    elif mode == "Alta/filtro_10":
        work = work[work["nivel_dificultad"].str.lower().str.contains("alta|filtro_10", na=False)]
    elif mode == "Plan de hoy":
        w1 = work[work["id"].isin(wrong)]
        w2 = work[~work["id"].isin(seen)]
        w3 = work[work["nivel_dificultad"].str.lower().str.contains("alta|filtro_10", na=False)]
        work = pd.concat([w1, w2, w3]).drop_duplicates("id")
    ids = work["id"].astype(str).tolist()
    random.shuffle(ids)
    return ids

def get_q(df, qid):
    row = df[df["id"].astype(str) == str(qid)]
    if row.empty:
        return None
    return row.iloc[0]

def login_page():
    st.title("🚑 TES Leixa — Acceso")
    st.caption(VERSION)
    st.info(f"Guardado: {st.session_state.store_mode}")

    with st.expander("Usuarios iniciales"):
        st.write("diego / tes2026 → administrador")
        st.write("anton / 1234")
        st.write("melisa / 1111")
        st.write("elvira / 2222")
        st.write("lucia / 3333")

    uid = st.text_input("Usuario")
    pwd = st.text_input("Contraseña", type="password")

    if st.button("Entrar", use_container_width=True):
        user = auth(st.session_state.store, uid, pwd)
        if user:
            clean = uid.strip().lower()
            st.session_state.logged = True
            st.session_state.uid = clean
            st.session_state.display_name = user.get("display_name", clean)
            st.session_state.role = user.get("role", "usuario")
            ok, msg = save_store(st.session_state.store)
            st.session_state.last_save = msg
            st.rerun()
        else:
            st.error("Usuario o contraseña incorrectos.")

    st.divider()
    if st.button("Restablecer usuarios iniciales", use_container_width=True):
        st.session_state.store = default_store()
        ok, msg = save_store(st.session_state.store)
        st.session_state.store_mode = "Archivo local reiniciado"
        st.session_state.last_save = msg
        st.success("Usuarios restablecidos. Ahora entra con diego / tes2026.")
        st.rerun()

def main_page():
    df = load_bank()
    store = st.session_state.store
    p = progress(store, st.session_state.uid)

    st.title("🚑 TES Leixa — Test táctil")
    st.caption(VERSION)

    total = len(df)
    seen = len(seen_ids(p))
    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Banco", total)
    c2.metric("Vistas", seen)
    c3.metric("No vistas", max(total - seen, 0))
    c4.metric("Fallos pendientes", len(p.get("wrong_ids", [])))

    with st.sidebar:
        st.write(f"Usuario: **{st.session_state.display_name}**")
        st.write(f"Guardado: **{st.session_state.store_mode}**")
        st.write(f"Último guardado: {st.session_state.last_save}")
        mode = st.radio("Modo", ["Plan de hoy", "Solo no respondidas", "Solo mis fallos", "Alta/filtro_10", "Libre"])
        module = st.selectbox("Módulo", ["Todos"] + sorted([x for x in df["modulo"].unique() if str(x).strip()]))
        if st.button("Nuevo bloque"):
            st.session_state.queue_key = ""
            st.session_state.queue = []
            st.session_state.queue_pos = 0
            st.session_state.answered = False
            st.session_state.current_qid = ""
            st.rerun()
        if st.button("Cerrar sesión"):
            st.session_state.logged = False
            st.rerun()

    qkey = f"{mode}|{module}"
    if st.session_state.queue_key != qkey or not st.session_state.queue:
        st.session_state.queue_key = qkey
        st.session_state.queue = build_queue(df, p, mode, module)
        st.session_state.queue_pos = 0
        st.session_state.answered = False
        st.session_state.current_qid = ""
        st.session_state.selected = None

    if not st.session_state.queue or st.session_state.queue_pos >= len(st.session_state.queue):
        st.success("Bloque terminado o sin preguntas.")
        return

    qid = st.session_state.queue[st.session_state.queue_pos]
    q = get_q(df, qid)
    if q is None:
        st.session_state.queue_pos += 1
        st.rerun()
        return

    correct = n(q.get("respuesta_correcta")).upper()

    st.divider()
    st.write(f"**Pregunta {st.session_state.queue_pos + 1} de {len(st.session_state.queue)}**")
    st.caption(f"{n(q.get('id'))} · {n(q.get('modulo'))} · {n(q.get('tema'))} · {n(q.get('nivel_dificultad'))}")
    st.markdown(f"### {n(q.get('enunciado'))}")

    if st.session_state.answered and st.session_state.current_qid == qid:
        selected = st.session_state.selected
        if selected == correct:
            st.success("Correcto. No entra en repaso de fallos.")
        else:
            st.error(f"Incorrecto. Correcta: {correct}. {opt(q, correct)}")
            st.warning("Queda en 'Solo mis fallos'.")
            render_failure(q, selected, correct)

        if st.button("Siguiente pregunta", use_container_width=True):
            st.session_state.queue_pos += 1
            st.session_state.answered = False
            st.session_state.selected = None
            st.session_state.current_qid = ""
            st.rerun()
        return

    for L in ["A","B","C","D"]:
        if st.button(f"{L}. {opt(q,L)}", key=f"answer_{qid}_{L}", use_container_width=True):
            selected = L
            is_ok = selected == correct
            entry = {"timestamp": now_iso(), "id": qid, "modulo": n(q.get("modulo")), "tema": n(q.get("tema")),
                     "subtema": n(q.get("subtema")), "dificultad": n(q.get("nivel_dificultad")),
                     "respuesta_usuario": selected, "respuesta_correcta": correct, "correcta": int(is_ok)}
            p["answered"].append(entry)
            if is_ok:
                if qid not in p["correct_ids"]:
                    p["correct_ids"].append(qid)
                if qid in p["wrong_ids"]:
                    p["wrong_ids"].remove(qid)
            else:
                if qid not in p["wrong_ids"]:
                    p["wrong_ids"].append(qid)
            ok, msg = save_store(store)
            st.session_state.last_save = msg
            st.session_state.answered = True
            st.session_state.selected = selected
            st.session_state.current_qid = qid
            st.rerun()

init()
if st.session_state.store is None:
    st.session_state.store, st.session_state.store_mode = load_store()
if not st.session_state.logged:
    login_page()
else:
    main_page()
